import{_ as e,a as t,b as o,c as n,d as p,e as l}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as d,o as i,c as r,a2 as s}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"IP geolokace a správa uživatelů","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/Other/ip-geolocation-and-user-management.md","filePath":"cs-CZ/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),u={name:"cs-CZ/Other/ip-geolocation-and-user-management.md"};function v(c,a,h,k,b,y){return i(),r("div",null,[...a[0]||(a[0]=[s('<h1 id="ip-geolokace-a-sprava-uzivatelu" tabindex="-1">IP geolokace a správa uživatelů <a class="header-anchor" href="#ip-geolokace-a-sprava-uzivatelu" aria-label="Permalink to &quot;IP geolokace a správa uživatelů&quot;">​</a></h1><p>IP geolokace převádí IP adresy v záznamech uploaderů, přihlášených zařízeních a podobných logách na přibližné lokace.</p><p>Po nastavení může administrace jasněji ukazovat původ uploadů a přístupů. Správa uživatelů zároveň umožňuje blokovat nebo obnovit upload pro podezřelé IP adresy.</p><h2 id="kde-nastavit" tabindex="-1">Kde nastavit <a class="header-anchor" href="#kde-nastavit" aria-label="Permalink to &quot;Kde nastavit&quot;">​</a></h2><p>Otevřete:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+e+`" alt="IP geolokace" loading="lazy"></p><h2 id="dostupna-nastaveni" tabindex="-1">Dostupná nastavení <a class="header-anchor" href="#dostupna-nastaveni" aria-label="Permalink to &quot;Dostupná nastavení&quot;">​</a></h2><p>Novější tok IP geolokace podporuje více zdrojů a nespoléhá jen na jednu mapovou službu.</p><table tabindex="0"><thead><tr><th>Nastavení</th><th>Účel</th></tr></thead><tbody><tr><td>Jazyk IP geolokace</td><td>Vybere jazyk zobrazení, například angličtinu, zjednodušenou čínštinu, japonštinu, francouzštinu a další.</td></tr><tr><td>MaxMind Account ID</td><td>Account ID MaxMind pro MaxMind GeoLite Web Service.</td></tr><tr><td>MaxMind License Key</td><td>License Key MaxMind.</td></tr><tr><td>Tencent Map Key</td><td>Klíč Tencent Location Service. Užitečný pro čínské adresy a IP z pevninské Číny.</td></tr><tr><td>ipapi Key</td><td>Klíč APILayer ipapi. Podporuje vícejazyčnou IP geolokaci.</td></tr></tbody></table><p>Vyplňte jen služby, které potřebujete. Není nutné konfigurovat každé pole.</p><p>Pokud nezadáte žádný klíč, ImgBed se stále pokusí použít vestavěné bezplatné zdroje, ale stabilita, jazyková podpora a přesnost mohou být nižší než u služby nastavené vámi.</p><h2 id="doporucene-volby" tabindex="-1">Doporučené volby <a class="header-anchor" href="#doporucene-volby" aria-label="Permalink to &quot;Doporučené volby&quot;">​</a></h2><p>Pokud potřebujete hlavně čínské adresy:</p><ol><li>Nastavte jazyk IP geolokace na zjednodušenou čínštinu.</li><li>Nastavte Tencent Map Key.</li><li>Volitelně přidejte MaxMind nebo ipapi jako záložní zdroje.</li></ol><p>Pokud potřebujete hlavně anglické nebo vícejazyčné adresy:</p><ol><li>Vyberte požadovaný jazyk.</li><li>Nastavte MaxMind Account ID a License Key.</li><li>Přidejte ipapi Key, pokud chcete lepší vícejazyčné výsledky.</li></ol><h2 id="nastaveni-maxmind" tabindex="-1">Nastavení MaxMind <a class="header-anchor" href="#nastaveni-maxmind" aria-label="Permalink to &quot;Nastavení MaxMind&quot;">​</a></h2><p>MaxMind potřebuje:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>Account ID najdete v dashboardu MaxMind a License Key vygenerujete na stránce License Keys.</p><p><img src="`+t+'" alt="Konfigurace klíče MaxMind" loading="lazy"></p><p>Po vygenerování vložte Account ID a License Key do ImgBed a uložte.</p><p>Bezplatný plán MaxMind stačí pro běžné použití, ale má limity požadavků. Po vyčerpání limitu ImgBed zkusí další dostupné zdroje.</p><h2 id="nastaveni-ipapi" tabindex="-1">Nastavení ipapi <a class="header-anchor" href="#nastaveni-ipapi" aria-label="Permalink to &quot;Nastavení ipapi&quot;">​</a></h2><p>ipapi používá APILayer API Key.</p><p>Otevřete konzoli ipapi a zkopírujte zobrazený API Key.</p><p><img src="'+o+'" alt="Konfigurace ipapi" loading="lazy"></p><p>Vložte ho do pole <code>ipapi Key</code> v ImgBed a uložte.</p><p>ipapi podporuje vícejazyčnou IP geolokaci a hodí se, když chcete zobrazovat adresy ve vybraném jazyce. Bezplatný plán má také limity. Po jejich vyčerpání ImgBed zkusí další dostupné zdroje.</p><h2 id="nastaveni-tencent-map-key" tabindex="-1">Nastavení Tencent Map Key <a class="header-anchor" href="#nastaveni-tencent-map-key" aria-label="Permalink to &quot;Nastavení Tencent Map Key&quot;">​</a></h2><p>Tencent Map Key je užitečný pro čínské adresy, zejména IP z pevninské Číny.</p><p>Při vytváření klíče v Tencent Location Service zapněte:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>Po vytvoření vložte klíč do <code>Tencent Map Key</code> a uložte.</p><p>Pokud potřebujete jen základní čínskou IP geolokaci, Tencent Map Key stačí pro začátek.</p><h2 id="co-kontrolovat-ve-sprave-uzivatelu" tabindex="-1">Co kontrolovat ve Správě uživatelů <a class="header-anchor" href="#co-kontrolovat-ve-sprave-uzivatelu" aria-label="Permalink to &quot;Co kontrolovat ve Správě uživatelů&quot;">​</a></h2><p>Správa uživatelů je dostupná nahoře v administraci.</p><p><img src="'+n+'" alt="Správa uživatelů" loading="lazy"></p><p>Správa uživatelů ukazuje upload aktivitu podle IP:</p><table tabindex="0"><thead><tr><th>Pole</th><th>Popis</th></tr></thead><tbody><tr><td>IP zdroj</td><td>Zdrojová IP adresa uploaderu.</td></tr><tr><td>Adresa</td><td>Přibližná lokace zjištěná z IP.</td></tr><tr><td>Celková velikost uploadu</td><td>Celková velikost souborů nahraných z této IP.</td></tr><tr><td>Počet uploadů</td><td>Počet uploadů z této IP.</td></tr><tr><td>Upload povolen</td><td>Zapnuto znamená povolené uploady. Vypnuto znamená blokované uploady.</td></tr></tbody></table><p>Klikněte na šipku vlevo pro rozbalení seznamu souborů nahraných z dané IP.</p><p>Seznam souborů ukazuje název, náhled, velikost, výsledek moderace, stav souboru a čas uploadu. Pokud uploady vypadají podezřele, nejprve rozbalte IP, zkontrolujte soubory a potom rozhodněte, zda blokovat další uploady.</p><p>Pokud je IP podezřelá, vypněte <code>Upload allowed</code>. Budoucí uploady z této IP budou blokované.</p><h2 id="vyhledavani-razeni-a-pokrocile-filtry" tabindex="-1">Vyhledávání, řazení a pokročilé filtry <a class="header-anchor" href="#vyhledavani-razeni-a-pokrocile-filtry" aria-label="Permalink to &quot;Vyhledávání, řazení a pokročilé filtry&quot;">​</a></h2><p>Nahoře ve Správě uživatelů můžete hledat podle zdrojové IP nebo adresy.</p><p>Řaďte podle času, počtu uploadů nebo celkové velikosti a najděte nedávné uploadery, časté uploadery nebo IP s vysokým využitím.</p><p>Pro hlubší kontrolu otevřete pokročilé filtry.</p><p><img src="'+p+'" alt="Pokročilé filtry" loading="lazy"></p><p>Pokročilé filtry podporují:</p><table tabindex="0"><thead><tr><th>Filtr</th><th>Použití</th></tr></thead><tbody><tr><td>Časový rozsah</td><td>Zobrazí IP, které nahrávaly soubory ve vybraném období.</td></tr><tr><td>Stav přístupu</td><td>Filtruje podle normálních, blokovaných a podobných stavů.</td></tr><tr><td>Allow/block list</td><td>Filtruje podle allowlist, blocklist nebo nenastaveného stavu.</td></tr><tr><td>Typ souboru</td><td>Zobrazí IP, které nahrávaly obrázky, videa, audio, dokumenty, kód nebo jiné soubory.</td></tr><tr><td>Velikost souboru</td><td>Filtruje podle rozsahu velikosti nahraných souborů.</td></tr><tr><td>Věkový rating</td><td>Filtruje podle nenastaveného, General, R12+, R16+, R18 a podobných ratingů.</td></tr><tr><td>Stav souboru</td><td>Filtruje podle aktuálního stavu souboru pro vyšetření neobvyklých souborů.</td></tr></tbody></table><p>Klikněte na <code>Apply Filters</code> pro použití. <code>Reset</code> vrátí všechna data.</p><h2 id="mobilni-zobrazeni" tabindex="-1">Mobilní zobrazení <a class="header-anchor" href="#mobilni-zobrazeni" aria-label="Permalink to &quot;Mobilní zobrazení&quot;">​</a></h2><p>Na mobilu se Správa uživatelů přepne do kartového rozložení.</p><p><img src="'+l+`" alt="Mobilní správa uživatelů" loading="lazy"></p><p>Každá karta ukazuje IP, adresu, celkovou velikost uploadu, počet uploadů a přepínač povolení uploadu. Uživatelé se dají spravovat bez vodorovného posouvání tabulky.</p><h2 id="pokud-lokace-vypada-spatne" tabindex="-1">Pokud lokace vypadá špatně <a class="header-anchor" href="#pokud-lokace-vypada-spatne" aria-label="Permalink to &quot;Pokud lokace vypadá špatně&quot;">​</a></h2><p>IP geolokace je přibližná. Není to přesná adresa ulice.</p><p>Pokud uživatel používá proxy, datacentrum, cloudový server nebo přeshraniční síť, zobrazená lokace se může lišit od skutečné.</p><p>Používejte tuto funkci pro hrubé pochopení původu, hledání neobvyklých uploadů a podporu rozhodování o blokování. Nepovažujte ji za přesné sledování.</p><h2 id="bezne-situace" tabindex="-1">Běžné situace <a class="header-anchor" href="#bezne-situace" aria-label="Permalink to &quot;Běžné situace&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Situace</th><th>Význam</th></tr></thead><tbody><tr><td>Adresa je prázdná</td><td>IP se možná ještě nepodařilo vyřešit nebo je aktuální zdroj dočasně nedostupný.</td></tr><tr><td>Jazyk adresy je špatný</td><td>Zkontrolujte jazyk IP geolokace a zda je nastaven zdroj podporující tento jazyk.</td></tr><tr><td>Adresa ukazuje datacentrum</td><td>Mnoho proxy, cloudových serverů a crawlerů se zobrazuje jako datacentrum nebo ISP.</td></tr><tr><td>Počet uploadů je vysoký</td><td>Tuto IP pečlivě zkontrolujte a v případě potřeby blokujte uploady.</td></tr><tr><td>Celková velikost uploadu je velká</td><td>Seřaďte nebo filtrujte, rozbalte IP a zkontrolujte konkrétní soubory.</td></tr><tr><td>Obnova po blokaci</td><td>Znovu zapněte <code>Upload allowed</code>.</td></tr></tbody></table><h2 id="rychly-postup" tabindex="-1">Rychlý postup <a class="header-anchor" href="#rychly-postup" aria-label="Permalink to &quot;Rychlý postup&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Otevřete IP Geolocation v Other Settings</span></span>
<span class="line"><span>-&gt; Vyberte jazyk IP geolokace</span></span>
<span class="line"><span>-&gt; Podle potřeby vyplňte MaxMind, Tencent Map nebo ipapi</span></span>
<span class="line"><span>-&gt; Uložte nastavení</span></span>
<span class="line"><span>-&gt; Otevřete Správu uživatelů</span></span>
<span class="line"><span>-&gt; Zkontrolujte IP zdroj, adresu, celkovou velikost a počet uploadů</span></span>
<span class="line"><span>-&gt; Použijte vyhledávání, řazení nebo pokročilé filtry pro hledání neobvyklých IP</span></span>
<span class="line"><span>-&gt; Podle potřeby povolte nebo blokujte uploady</span></span></code></pre></div>`,64)])])}const j=d(u,[["render",v]]);export{P as __pageData,j as default};
